/**
 * QA Analysis Stage — Five-layer code understanding progress display.
 *
 * Owns the qaAnalysisContainer DOM. Renders analysis phases as a vertical
 * progress tracker with real-time metrics. Scenarios appear as cards as
 * they're generated by the LLM layer.
 */
class QaAnalysis {
  constructor(panel) {
    this._panel = panel;
    this._container = null;
    this._phases = [];        // phase DOM elements
    this._scenarios = [];     // received scenarios
    this._lintFindings = [];  // F27 item 5 — deterministic lint findings batch
    this._testingGuidance = null; // F27 P11 — Architect testing guidance block
    this._scenarioListEl = null;
    this._cancelBtn = null;
    this._metricsEl = null;
    this._isComplete = false;
    this._isCancelled = false;
  }

  init() {
    this._container = document.getElementById('qaAnalysisContainer');
    this._panel.registerAnalysis(this);
    this._render();
  }

  _render() {
    if (!this._container) return;
    this._container.innerHTML = '';

    // ── P10: Catalog-health strip ──
    this._catalogStrip = document.createElement('div');
    this._catalogStrip.className = 'qa-analysis-catalog-strip';
    this._catalogStrip.style.display = 'none';
    this._container.appendChild(this._catalogStrip);

    // ── Progress tracker ──
    var tracker = document.createElement('div');
    tracker.className = 'qa-analysis-tracker';

    var phaseNames = [
      { id: 'fetching_diff', label: 'Fetching PR Diff', icon: '\u25CB' },
      { id: 'roslyn_blast_radius', label: 'Blast Radius Analysis', icon: '\u25CB' },
      { id: 'semantic_analysis', label: 'Semantic Analysis (Roslyn)', icon: '\u25CB' },
      { id: 'di_validation', label: 'DI Registry Validation', icon: '\u25CB' },
      { id: 'scenario_generation', label: 'Scenario Generation (LLM)', icon: '\u25CB' },
      { id: 'complete', label: 'Complete', icon: '\u25CB' }
    ];

    this._phases = [];
    for (var i = 0; i < phaseNames.length; i++) {
      var p = phaseNames[i];
      var phaseEl = document.createElement('div');
      phaseEl.className = 'qa-analysis-phase';
      phaseEl.dataset.phase = p.id;

      var iconEl = document.createElement('span');
      iconEl.className = 'qa-phase-icon';
      iconEl.textContent = p.icon;

      var labelEl = document.createElement('span');
      labelEl.className = 'qa-phase-label';
      labelEl.textContent = p.label;

      var detailEl = document.createElement('span');
      detailEl.className = 'qa-phase-detail';

      phaseEl.appendChild(iconEl);
      phaseEl.appendChild(labelEl);
      phaseEl.appendChild(detailEl);
      tracker.appendChild(phaseEl);
      this._phases.push({ el: phaseEl, iconEl: iconEl, detailEl: detailEl, id: p.id });
    }

    this._container.appendChild(tracker);

    // ── Metrics bar ──
    var metricsBar = document.createElement('div');
    metricsBar.className = 'qa-analysis-metrics';
    metricsBar.id = 'qaAnalysisMetrics';
    this._container.appendChild(metricsBar);
    this._metricsEl = metricsBar;

    // ── Cancel button ──
    var cancelRow = document.createElement('div');
    // Two distinct marker classes so `_showProceedButton`'s idempotency
    // check can target ONLY the proceed row. Previously both rows used
    // the same `qa-analysis-actions` class and the guard
    // `if (this._container.querySelector('.qa-analysis-actions')) return;`
    // would always match the cancel row → the proceed button was never
    // shown when analysis completed.
    cancelRow.className = 'qa-analysis-actions qa-analysis-cancel-row';
    this._cancelBtn = document.createElement('button');
    this._cancelBtn.className = 'qa-btn';
    this._cancelBtn.textContent = 'Cancel Analysis';
    this._cancelBtn.addEventListener('click', () => this._cancelAnalysis());
    cancelRow.appendChild(this._cancelBtn);
    this._container.appendChild(cancelRow);

    // ── Scenario list (appears as scenarios stream in) ──
    var scenarioHeader = document.createElement('div');
    scenarioHeader.className = 'qa-analysis-scenario-header';
    scenarioHeader.style.display = 'none';
    scenarioHeader.id = 'qaScenarioHeader';

    var headerTitle = document.createElement('h4');
    headerTitle.textContent = 'Generated Scenarios';
    scenarioHeader.appendChild(headerTitle);

    var countEl = document.createElement('span');
    countEl.className = 'qa-scenario-count';
    countEl.id = 'qaScenarioCount';
    scenarioHeader.appendChild(countEl);
    this._container.appendChild(scenarioHeader);

    this._scenarioListEl = document.createElement('div');
    this._scenarioListEl.className = 'qa-analysis-scenarios';
    this._container.appendChild(this._scenarioListEl);
  }

  // ── Event Handlers (called by QaPanel) ──

  onProgress(data) {
    console.log('[QA-DIAG] onProgress:', data.phase, data.phaseIndex + '/' + data.totalPhases,
      data.percentComplete + '%', data.detail || '', data.metrics ? JSON.stringify(data.metrics) : '');
    this._isComplete = false;
    this._isCancelled = false;

    // Update phase tracker
    for (var i = 0; i < this._phases.length; i++) {
      var p = this._phases[i];
      if (i < data.phaseIndex) {
        p.el.classList.add('completed');
        p.el.classList.remove('active');
        p.iconEl.textContent = '\u25CF'; // ●
      } else if (i === data.phaseIndex) {
        p.el.classList.add('active');
        p.el.classList.remove('completed');
        p.iconEl.textContent = '\u25D4'; // ◔
        p.detailEl.textContent = data.detail || '';
      } else {
        p.el.classList.remove('active', 'completed');
        p.iconEl.textContent = '\u25CB'; // ○
        p.detailEl.textContent = '';
      }
    }

    // Update metrics
    if (data.metrics && this._metricsEl) {
      var parts = [];
      if (data.metrics.filesAnalyzed != null) parts.push(data.metrics.filesAnalyzed + ' files');
      if (data.metrics.linesChanged != null) parts.push(data.metrics.linesChanged + ' lines');
      if (data.metrics.impactZonesFound != null) parts.push(data.metrics.impactZonesFound + ' impact zones');
      if (data.metrics.elapsedMs != null) parts.push((data.metrics.elapsedMs / 1000).toFixed(1) + 's');
      // F27 P11: Architect-complete summary — when the orchestrator forwards
      // testingGuidance counts on the metrics envelope, surface them inline
      // so curators see "Architect projected N code paths + M error modes"
      // before clicking Review Scenarios. Backend may emit any of
      // codePathCount / errorModeCount / featureFlagComboCount / coverageGapCount.
      if (data.metrics.codePathCount != null) parts.push(data.metrics.codePathCount + ' code paths');
      if (data.metrics.errorModeCount != null) parts.push(data.metrics.errorModeCount + ' error modes');
      if (data.metrics.featureFlagComboCount != null) parts.push(data.metrics.featureFlagComboCount + ' flag combos');
      if (data.metrics.coverageGapCount != null && data.metrics.coverageGapCount > 0) {
        parts.push(data.metrics.coverageGapCount + ' coverage gap'
          + (data.metrics.coverageGapCount !== 1 ? 's' : ''));
      }
      this._metricsEl.textContent = parts.join(' \u00B7 '); // middle dot separator
    }

    // If complete phase, enable proceed.
    // Guarded by !_isComplete because the backend emits a final
    // phase=complete event per pipeline stage (analyze, lint, finalize),
    // and without this guard _showProceedButton would stack a button
    // for every emit — producing the duplicate "Review Scenarios"
    // buttons users saw in the curation handoff.
    if (data.phase === 'complete' && !this._isComplete) {
      console.log('[QA-DIAG] *** ANALYSIS COMPLETE — scenarios received:', this._scenarios.length);
      this._isComplete = true;
      if (this._cancelBtn) this._cancelBtn.style.display = 'none';
      this._showProceedButton();
    }
  }

  onCancelled(data) {
    console.log('[QA-DIAG] onCancelled:', data.reason);
    this._isCancelled = true;
    // Mark the active phase as cancelled
    for (var i = 0; i < this._phases.length; i++) {
      var p = this._phases[i];
      if (p.el.classList.contains('active')) {
        p.el.classList.remove('active');
        p.iconEl.textContent = '\u2715'; // ✕
        p.detailEl.textContent = 'Cancelled: ' + (data.reason || 'user');
        break;
      }
    }
    if (this._cancelBtn) {
      this._cancelBtn.textContent = 'Back to Input';
      this._cancelBtn.onclick = () => this._panel.goToStage('input');
    }
  }

  onWarning(data) {
    var msg = data.message || data.warning || 'Unknown warning';
    console.warn('[QA-DIAG] onWarning:', data.warning, msg);

    // Show degradation indicator on the active phase
    for (var i = 0; i < this._phases.length; i++) {
      var p = this._phases[i];
      if (p.el.classList.contains('active')) {
        p.el.classList.add('degraded');
        var existing = p.detailEl.textContent;
        p.detailEl.textContent = (existing ? existing + ' ' : '') + '\u26A0 ' + msg;
        break;
      }
    }

    // Also toast the warning
    if (window.edogToast) window.edogToast(msg, 'warning');
  }

  // ── F27 P4 — Inline LLM / scenario-generation error panel ──
  //
  // Routes QaError events that originate from the scenario_generation
  // phase (errorCode === "NO_SCENARIOS_GENERATED" or "LLM_PROVIDER_*")
  // away from the toast-only top-level handler in qa-panel.js and into
  // an inline panel under the analysis tracker so the user sees an
  // actionable, persistent message + an optional Retry CTA.
  //
  // Called by QaPanel._handleError when the error payload looks like
  // an analysis-phase failure.
  onAnalysisPhaseError(data) {
    var msg = (data && data.message) || 'Unknown analysis error';
    var code = (data && (data.errorCode || data.ErrorCode)) || 'UNKNOWN';
    var recoverable = !!(data && (data.recoverable || data.Recoverable));
    console.error('[QA-DIAG] onAnalysisPhaseError:', code, msg, 'recoverable=' + recoverable);

    // Mark the scenario_generation phase as failed (red ✕).
    for (var i = 0; i < this._phases.length; i++) {
      var p = this._phases[i];
      if (p.el.dataset.phase === 'scenario_generation') {
        p.el.classList.remove('active');
        p.el.classList.add('failed');
        p.iconEl.textContent = '\u2715';
        p.detailEl.textContent = code;
        break;
      }
    }

    // Render (or replace) the inline error panel above the scenario list.
    if (!this._container) return;
    var panel = this._container.querySelector('.qa-analysis-error');
    if (!panel) {
      panel = document.createElement('div');
      panel.className = 'qa-analysis-error';
      panel.setAttribute('role', 'alert');
      var anchor = this._container.querySelector('.qa-scenario-preview-list') || this._container.firstChild;
      if (anchor && anchor.parentNode === this._container) {
        this._container.insertBefore(panel, anchor);
      } else {
        this._container.appendChild(panel);
      }
    }
    panel.innerHTML = '';

    var icon = document.createElement('span');
    icon.className = 'qa-analysis-error-icon';
    icon.textContent = '\u26A0';
    panel.appendChild(icon);

    var cause = data && data.cause;

    var body = document.createElement('div');
    body.className = 'qa-analysis-error-body';

    var title = document.createElement('div');
    title.className = 'qa-analysis-error-title';
    title.textContent = this._titleForErrorCode(code, cause);
    body.appendChild(title);

    var message = document.createElement('div');
    message.className = 'qa-analysis-error-message';
    message.textContent = msg;
    body.appendChild(message);

    var actions = document.createElement('div');
    actions.className = 'qa-analysis-error-actions';

    if (code === 'NO_SCENARIOS_GENERATED' || code.indexOf('LLM_PROVIDER_') === 0) {
      // Only show the "Configure LLM provider" CTA when the failure is
      // actually a config issue. When the V2 pipeline ran but failed
      // internally (zone failed, quarantined, projection rejected, etc.)
      // the cause field carries a v2_* tag — skip the config link.
      var isPipelineFailure = cause && cause.indexOf('v2_') === 0;
      if (!isPipelineFailure) {
        var configLink = document.createElement('a');
        configLink.href = 'https://aka.ms/edog-studio-llm-setup';
        configLink.target = '_blank';
        configLink.rel = 'noopener noreferrer';
        configLink.textContent = 'Configure LLM provider \u2192';
        actions.appendChild(configLink);
      }
    }

    if (recoverable) {
      var retryBtn = document.createElement('button');
      retryBtn.type = 'button';
      retryBtn.className = 'qa-analysis-error-retry';
      retryBtn.textContent = 'Retry analysis';
      retryBtn.onclick = () => {
        if (this._panel && typeof this._panel.goToStage === 'function') {
          this._panel.goToStage('input');
        }
      };
      actions.appendChild(retryBtn);
    }

    if (actions.children.length > 0) {
      body.appendChild(actions);
    }
    panel.appendChild(body);
  }

  _titleForErrorCode(code, cause) {
    // When the V2 pipeline ran but failed internally, use a more
    // specific title keyed on the cause instead of the generic
    // "No scenarios were generated" that implies a config issue.
    if (code === 'NO_SCENARIOS_GENERATED' && cause) {
      switch (cause) {
        case 'v2_zone_failed':
          return 'LLM pipeline validation failed';
        case 'v2_budget_skipped':
          return 'LLM budget exhausted';
        case 'v2_projection_rejected':
          return 'Scenario projection failed';
        case 'v2_all_quarantined':
          return 'All scenarios quarantined';
        case 'v2_no_testable_changes':
          return 'No testable changes detected';
      }
    }
    switch (code) {
      case 'LLM_PROVIDER_AUTH':
        return 'LLM credentials rejected';
      case 'LLM_PROVIDER_RATE_LIMIT':
        return 'LLM provider rate-limited';
      case 'LLM_PROVIDER_TIMEOUT':
        return 'LLM request timed out';
      case 'LLM_PROVIDER_PARSE':
        return 'LLM returned malformed response';
      case 'LLM_PROVIDER_NETWORK':
        return 'LLM transport failure';
      case 'NO_SCENARIOS_GENERATED':
        return 'No scenarios were generated';
      default:
        return 'Analysis error (' + code + ')';
    }
  }

  onScenarioGenerated(data) {
    var scn = data.scenario;
    console.log('[QA-DIAG] onScenarioGenerated:', scn ? scn.title : '(null)', 
      'type=' + (scn && scn.stimulusType), 'cat=' + (scn && scn.category),
      'confidence=' + (scn && scn.metadata && scn.metadata.confidence),
      'index=' + data.scenarioIndex + '/' + data.totalExpected);
    if (!scn) return;
    // Defence-in-depth dedup. The qa topic stream's Phase 1 snapshot
    // (EdogPlaygroundHub.SubscribeToTopic) would otherwise replay every
    // QaScenarioGenerated event into this method on each fresh
    // subscription, doubling the scenario list. The primary fix lives
    // in qa-panel.js (subscribe-once at init), but skipping by id
    // here means a future regression on the subscription lifecycle
    // can't reintroduce the duplicate cards.
    if (scn.id) {
      for (var j = 0; j < this._scenarios.length; j++) {
        if (this._scenarios[j] && this._scenarios[j].id === scn.id) return;
      }
    }
    this._scenarios.push(scn);

    // Show header
    var header = document.getElementById('qaScenarioHeader');
    if (header) header.style.display = '';
    var countEl = document.getElementById('qaScenarioCount');
    if (countEl) countEl.textContent = this._scenarios.length + (data.totalExpected ? ' / ~' + data.totalExpected : '');

    // Add scenario card
    if (this._scenarioListEl) {
      var card = document.createElement('div');
      card.className = 'qa-card qa-scenario-preview';

      var titleEl = document.createElement('div');
      titleEl.className = 'qa-scenario-preview-title';
      titleEl.textContent = scn.title;

      var metaEl = document.createElement('div');
      metaEl.className = 'qa-scenario-preview-meta';
      var catBadge = document.createElement('span');
      catBadge.className = 'qa-category-badge qa-cat-' + (scn.category || 'unknown').replace(/_/g, '-');
      catBadge.textContent = (scn.category || 'unknown').replace(/_/g, ' ');
      metaEl.appendChild(catBadge);

      if (scn.metadata && scn.metadata.confidence != null) {
        var confEl = document.createElement('span');
        confEl.className = 'qa-confidence';
        confEl.textContent = Math.round(scn.metadata.confidence * 100) + '% confidence';
        metaEl.appendChild(confEl);
      }

      card.appendChild(titleEl);
      card.appendChild(metaEl);
      this._scenarioListEl.appendChild(card);

      // Scroll to bottom
      card.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
  }

  // ── Actions ──

  _cancelAnalysis() {
    var conn = this._panel.getConnection();
    if (!conn) return;
    var corrId = this._panel.getCorrelationId();
    conn.invoke('QaCancelAnalysis', corrId).catch(function(err) {
      console.error('[QA] Cancel analysis failed:', err);
    });
  }

  /**
   * Receive the deterministic linter batch produced after scenario generation.
   * Findings flow into the curation stage so reviewers see badges and the
   * findings panel alongside the scenario list. Severity counts also surface
   * on the analysis-phase footer as a heads-up.
   */
  onLintFindings(data) {
    console.log('[QA-DIAG] onLintFindings:', (data && data.findings ? data.findings.length : 0), 
      'findings, errors=' + (data && data.errorCount), 'warnings=' + (data && data.warningCount));
    if (!data) return;
    this._lintFindings = Array.isArray(data.findings) ? data.findings.slice() : [];
    // Surface a non-toast badge in the metrics line — purely informational.
    var errCount = data.errorCount || 0;
    var warnCount = data.warningCount || 0;
    if (this._metricsEl && (errCount + warnCount) > 0) {
      var existing = this._metricsEl.textContent || '';
      var badge = '\u2696 ' + errCount + 'E / ' + warnCount + 'W lint';
      this._metricsEl.textContent = existing ? (existing + ' \u00B7 ' + badge) : badge;
    }
  }

  /**
   * F27 P11 wiring fix — receive the Architect testing-guidance block.
   * Stored on the analysis stage and handed off to qa-curation as the 4th
   * loadScenarios() argument so the curation UI can render the guidance
   * panel next to scenarios and lint findings.
   */
  onTestingGuidance(data) {
    if (!data) return;
    this._testingGuidance = data.testingGuidance || data.TestingGuidance || null;
    console.log('[QA-DIAG] onTestingGuidance: stored guidance with',
      this._testingGuidance && Array.isArray(this._testingGuidance.codePaths) ? this._testingGuidance.codePaths.length : 0,
      'code paths');
  }

  _showProceedButton() {
    if (!this._container) return;
    // Idempotent — silently bail if a proceed row is already in the DOM.
    // The container also hosts other action rows (e.g. the cancel row
    // emitted during `_render`) which share the `qa-analysis-actions`
    // class for styling, so we target a dedicated marker class instead
    // to avoid colliding with them and silently hiding the proceed
    // button forever.
    if (this._container.querySelector('.qa-analysis-proceed-row')) return;
    var row = document.createElement('div');
    row.className = 'qa-analysis-actions qa-analysis-proceed-row';
    var btn = document.createElement('button');
    btn.className = 'qa-btn primary';
    btn.textContent = 'Review Scenarios \u25B8';
    btn.addEventListener('click', () => {
      // Pass scenarios to curation stage
      if (this._panel._curation) {
        this._panel._curation.loadScenarios(this._scenarios, this._panel.getAnalysisId(), this._lintFindings, this._testingGuidance);
      }
      this._panel.goToStage('curation');
    });
    row.appendChild(btn);
    this._container.appendChild(row);
  }

  /** Get the generated scenarios */
  getScenarios() { return this._scenarios.slice(); }

  /** Reset for a new analysis */
  reset() {
    this._scenarios = [];
    this._lintFindings = [];
    this._testingGuidance = null;
    this._isComplete = false;
    this._isCancelled = false;
    this._render();
  }

  // ── P10: Catalog-health strip ──────────────────────────────────────

  /**
   * Render the catalog-health strip with provider status pills.
   * Called when catalog snapshot data arrives from the backend.
   *
   * @param {Object} snapshot — CatalogSnapshot JSON from /api/contract/catalog/{zoneId}
   */
  renderCatalogHealth(snapshot) {
    if (!this._catalogStrip || !snapshot) return;
    this._catalogStrip.style.display = 'flex';
    this._catalogStrip.innerHTML = '';

    // Snapshot metadata
    var meta = document.createElement('span');
    meta.className = 'catalog-strip-meta';
    meta.textContent = 'Catalog: ' + (snapshot.snapshotId || '---')
      + ' \u00B7 ' + (snapshot.slots ? snapshot.slots.length : 0) + ' slots';
    this._catalogStrip.appendChild(meta);

    // Provider status pills
    var providers = snapshot.providerStatus || {};
    var keys = Object.keys(providers);
    for (var i = 0; i < keys.length; i++) {
      var pill = document.createElement('span');
      pill.className = 'provider-status provider-status--' + providers[keys[i]];
      pill.textContent = keys[i] + ': ' + providers[keys[i]];
      this._catalogStrip.appendChild(pill);
    }
  }

  /**
   * Fetch the catalog snapshot from the dev-server proxy.
   *
   * @param {string} zoneId — impact zone identifier
   */
  fetchCatalogHealth(zoneId) {
    console.log('[QA-DIAG] fetchCatalogHealth:', zoneId);
    var self = this;
    fetch('/api/contract/catalog/' + encodeURIComponent(zoneId))
      .then(function (r) { return r.json(); })
      .then(function (snapshot) {
        console.log('[QA-DIAG] catalogHealth response:', snapshot.snapshotId, 
          'slots=' + (snapshot.slots ? snapshot.slots.length : 0),
          'providers=' + JSON.stringify(snapshot.providerStatus));
        self.renderCatalogHealth(snapshot);
      })
      .catch(function (err) { console.error('[QA-DIAG] catalog-health fetch FAILED:', err); });
  }
}
